@Injectable()
export class PrivacyGatekeeper {
  async check(userId: string, contentOwnerId: string): Promise<DataProcessResult<{ allowed: boolean }>> {
    const settings = await this.privacySettings.get(userId);  // live DATABASE read, no cache
    return DataProcessResult.success({ allowed: !settings.isBlockedBy(contentOwnerId) });
  }
}
